export const BLOG_CATEGORIES = [...new Set(BLOG_POSTS.map((p) => p.category))];

export function getPost(slug: string): BlogPost | undefined {
  return BLOG_POSTS.find((p) => p.slug === slug);
}

export type BlogSort = "newest" | "oldest" | "az" | "za";

export const SORT_OPTIONS: { value: BlogSort; label: string }[] = [
  { value: "newest", label: "Newest first" },
  { value: "oldest", label: "Oldest first" },
  { value: "az", label: "A → Z" },
  { value: "za", label: "Z → A" },
];

export function getFilteredPosts(
  category?: string | null,
  query?: string | null,
) {
  let posts = BLOG_POSTS;
  if (category) posts = posts.filter((p) => p.category === category);
  if (query) {
    const q = query.toLowerCase();
    posts = posts.filter(
      (p) =>
        p.title.toLowerCase().includes(q) ||
        p.excerpt.toLowerCase().includes(q) ||
        p.category.toLowerCase().includes(q) ||
        p.author.toLowerCase().includes(q),
    );
  }
  return posts;
}

export function sortPosts(posts: BlogPost[], sort: BlogSort): BlogPost[] {
  const copy = [...posts];
  switch (sort) {
    case "oldest":
      return copy.sort((a, b) => a.dateISO.localeCompare(b.dateISO));
    case "az":
      return copy.sort((a, b) => a.title.localeCompare(b.title));
    case "za":
      return copy.sort((a, b) => b.title.localeCompare(a.title));
    case "newest":
    default:
      return copy.sort((a, b) => b.dateISO.localeCompare(a.dateISO));
  }
}

export function getPaginatedPosts(
  posts: BlogPost[],
  page: number,
): { posts: BlogPost[]; totalPages: number; currentPage: number } {
  const totalPages = Math.max(1, Math.ceil(posts.length / POSTS_PER_PAGE));
  const safePage = Math.max(1, Math.min(page, totalPages));
  const start = (safePage - 1) * POSTS_PER_PAGE;
  return {
    posts: posts.slice(start, start + POSTS_PER_PAGE),
    totalPages,
    currentPage: safePage,
  };
}
